//! Integration tests for digital signature verification (`pdfsig`-equivalent).
//!
//! Fixtures are generated by `scripts/make_signature_fixtures.py` (pyHanko + a
//! self-signed RSA/SHA-256 cert we control, so the ground truth is known):
//!   sig_valid.pdf - one valid signature covering the whole file
//!   sig_two.pdf   - signed twice (two signature fields)
//!
//! The tampered and modified-after-signing cases are derived from
//! sig_valid.pdf at test time (mutate / append bytes), so they don't need to be
//! committed.
//!
//! NOTE: Poppler's `pdfsig` is not bundled in this environment, so the
//! cross-check is against the KNOWN GROUND TRUTH (we control the cert/key and
//! pyHanko independently confirms intact=valid), not against `pdfsig`. The
//! objective findings (cryptographic validity + coverage + signer details) are
//! exactly what a `pdfsig` cross-check would compare.

use std::path::PathBuf;

use oxide_engine::{
    ContentEngine, Coverage, LtvMaterial, PadesLevel, PdfSigner, RevocationStatus,
    SignatureOptions, SignatureStatus, SignatureTrust, SignatureValidity, VerifyOptions,
};

fn fixture(name: &str) -> PathBuf {
    PathBuf::from(env!("CARGO_MANIFEST_DIR"))
        .join("tests")
        .join("fixtures")
        .join(name)
}

fn fixture_bytes(name: &str) -> Vec<u8> {
    std::fs::read(fixture(name)).expect("fixture present (run make_signature_fixtures.py)")
}

fn fixture_pem(name: &str) -> String {
    let raw = std::fs::read_to_string(fixture(name)).expect("PEM fixture present");
    let mut pem = raw
        .lines()
        .filter(|line| !line.trim_start().starts_with('#'))
        .collect::<Vec<_>>()
        .join("\n");
    pem.push('\n');
    pem
}

fn test_signer() -> PdfSigner {
    PdfSigner::from_pem(
        &fixture_pem("sign_test_rsa_key.pem"),
        &fixture_pem("sign_test_rsa_cert.pem"),
        &[],
    )
    .expect("test signer parses")
}

fn test_timestamp_token_der() -> Vec<u8> {
    use cms::content_info::ContentInfo;
    use der::asn1::Any;
    use der::{Encode, Tag};

    let token = ContentInfo {
        content_type: const_oid::db::rfc5911::ID_DATA,
        content: Any::new(Tag::OctetString, b"oxide-test-rfc3161-token".to_vec()).unwrap(),
    };
    token.to_der().unwrap()
}

fn test_crl_der(signer: &PdfSigner, revoked_serial: &[u8]) -> Vec<u8> {
    use der::asn1::{BitString, GeneralizedTime};
    use der::{DateTime, Encode};
    use spki::AlgorithmIdentifierOwned;
    use x509_cert::crl::{CertificateList, RevokedCert, TbsCertList};
    use x509_cert::serial_number::SerialNumber;
    use x509_cert::time::Time;
    use x509_cert::Version;

    let cert = signer.signer_certificate();
    let alg = AlgorithmIdentifierOwned {
        oid: const_oid::ObjectIdentifier::new_unwrap("1.2.840.113549.1.1.11"),
        parameters: None,
    };
    let time = Time::GeneralTime(GeneralizedTime::from_date_time(
        DateTime::new(2026, 6, 22, 0, 0, 0).unwrap(),
    ));
    let crl = CertificateList {
        tbs_cert_list: TbsCertList {
            version: Version::V2,
            signature: alg.clone(),
            issuer: cert.tbs_certificate.issuer.clone(),
            this_update: time,
            next_update: Some(time),
            revoked_certificates: Some(vec![RevokedCert {
                serial_number: SerialNumber::new(revoked_serial).unwrap(),
                revocation_date: time,
                crl_entry_extensions: None,
            }]),
            crl_extensions: None,
        },
        signature_algorithm: alg,
        signature: BitString::from_bytes(&[0]).unwrap(),
    };
    crl.to_der().unwrap()
}

fn qpdf_check_if_available(name: &str, bytes: &[u8]) {
    if std::process::Command::new("qpdf")
        .arg("--version")
        .output()
        .is_err()
    {
        return;
    }
    let dir = PathBuf::from(env!("CARGO_TARGET_TMPDIR"))
        .join("signature_ltv_qpdf")
        .join(name);
    std::fs::create_dir_all(&dir).unwrap();
    let pdf = dir.join("out.pdf");
    std::fs::write(&pdf, bytes).unwrap();
    let output = std::process::Command::new("qpdf")
        .arg("--check")
        .arg(&pdf)
        .output()
        .expect("qpdf --check runs");
    assert!(
        output.status.success(),
        "qpdf --check failed\nstdout:\n{}\nstderr:\n{}",
        String::from_utf8_lossy(&output.stdout),
        String::from_utf8_lossy(&output.stderr)
    );
}

#[test]
fn rsa_signing_appends_valid_incremental_signature() {
    let original = fixture_bytes("minimal.pdf");
    let e = ContentEngine::open_bytes(original.clone()).unwrap();
    let options = SignatureOptions {
        field_name: "OxideSig1".to_string(),
        signer_name: Some("Oxide SDK Signing Test".to_string()),
        reason: Some("integration test".to_string()),
        location: Some("test suite".to_string()),
        signing_time: Some("D:20260622000000Z".to_string()),
        rect: Some([36.0, 36.0, 260.0, 96.0]),
        ..SignatureOptions::default()
    };

    let signed = e.sign(&test_signer(), &options).unwrap();
    assert!(
        signed.starts_with(&original),
        "incremental signing must preserve the original bytes as a prefix"
    );
    assert!(signed.len() > original.len());

    let signed_engine = ContentEngine::open_bytes(signed.clone()).unwrap();
    let reports = signed_engine.verify_signatures().unwrap();
    assert_eq!(reports.len(), 1);
    let r = &reports[0];
    assert_eq!(r.field_name.as_deref(), Some("OxideSig1"));
    assert_eq!(r.signer_name.as_deref(), Some("Oxide SDK Signing Test"));
    assert_eq!(r.reason.as_deref(), Some("integration test"));
    assert_eq!(r.location.as_deref(), Some("test suite"));
    assert_eq!(r.validity, SignatureValidity::Valid);
    assert_eq!(r.coverage, Coverage::WholeFile);
    assert_eq!(r.digest_algorithm.as_deref(), Some("SHA-256"));
    let cert = r.certificate.as_ref().expect("signer cert reported");
    assert!(cert.subject.contains("Oxide SDK Signing Test"));
    assert_eq!(cert.serial_hex, "20260801");

    let mut tampered = signed;
    let pos = tampered
        .windows(2)
        .position(|w| w == b"Hi")
        .expect("page content marker present");
    tampered[pos] = b'X';
    let tampered_engine = ContentEngine::open_bytes(tampered).unwrap();
    let tampered_report = &tampered_engine.verify_signatures().unwrap()[0];
    assert_eq!(tampered_report.validity, SignatureValidity::Invalid);
}

#[test]
fn timestamp_and_dss_ltv_material_are_reported_offline() {
    let original = fixture_bytes("basicapi.pdf");
    let signer = test_signer();
    let e = ContentEngine::open_bytes(original).unwrap();
    let options = SignatureOptions {
        field_name: "OxideLtvSig".to_string(),
        signer_name: Some("Oxide SDK LTV Test".to_string()),
        reason: Some("ltv integration test".to_string()),
        signing_time: Some("D:20260622000000Z".to_string()),
        timestamp_token_der: Some(test_timestamp_token_der()),
        contents_reserved_bytes: 32 * 1024,
        ..SignatureOptions::default()
    };

    let signed = e.sign(&signer, &options).unwrap();
    let signed_engine = ContentEngine::open_bytes(signed.clone()).unwrap();
    let signed_report = &signed_engine.verify_signatures().unwrap()[0];
    assert_eq!(signed_report.validity, SignatureValidity::Valid);
    assert_eq!(signed_report.coverage, Coverage::WholeFile);
    assert_eq!(signed_report.ltv.pades_level, PadesLevel::BaselineT);
    assert_eq!(signed_report.ltv.timestamp_token_count, 1);

    // The signer cert serial is 20260801 in the committed fixture.
    let revoked_crl = test_crl_der(&signer, &[0x20, 0x26, 0x08, 0x01]);
    let ltv = signed_engine
        .add_ltv_material(&LtvMaterial {
            crls_der: vec![revoked_crl],
            ..LtvMaterial::default()
        })
        .unwrap();
    assert!(
        ltv.starts_with(&signed),
        "LTV/DSS must append an incremental update without rewriting signed bytes"
    );
    qpdf_check_if_available("timestamp_and_dss", &ltv);

    let ltv_engine = ContentEngine::open_bytes(ltv).unwrap();
    let report = &ltv_engine.verify_signatures().unwrap()[0];
    assert_eq!(report.validity, SignatureValidity::Valid);
    assert_eq!(report.coverage, Coverage::ModifiedAfterSigning);
    assert_eq!(report.ltv.pades_level, PadesLevel::BaselineLT);
    assert!(report.ltv.dss_present);
    assert!(report.ltv.vri_matched);
    assert!(report.ltv.embedded_certs >= 1);
    assert_eq!(report.ltv.embedded_crls, 1);
    assert_eq!(
        report.ltv.revocation_status,
        RevocationStatus::RevokedByEmbeddedCrl
    );
}

#[test]
fn valid_signature_is_cryptographically_valid_with_cert_details() {
    let e = ContentEngine::open_bytes(fixture_bytes("sig_valid.pdf")).unwrap();
    let reports = e.verify_signatures().unwrap();
    assert_eq!(reports.len(), 1, "expected exactly one signature");
    let r = &reports[0];

    assert_eq!(r.validity, SignatureValidity::Valid);
    assert_eq!(r.coverage, Coverage::WholeFile);
    assert_eq!(r.digest_algorithm.as_deref(), Some("SHA-256"));

    let cert = r.certificate.as_ref().expect("signer cert reported");
    assert!(
        cert.subject.contains("Oxide Test Signer"),
        "subject was {}",
        cert.subject
    );
    assert_eq!(cert.serial_hex, "1234ABCD");
    // CORRECTED (was: asserted the old "Trust-chain validation ... not verdict
    // gates" scope note, which encoded the H-3 bug that trust was never
    // evaluated). The honest note now separates integrity from trust, and with
    // no anchors configured trust is explicitly NOT verified — never "trusted".
    assert_eq!(r.trust, SignatureTrust::NotVerified);
    assert_eq!(r.status, SignatureStatus::ValidUntrusted);
    assert!(
        r.note.to_lowercase().contains("trust not verified"),
        "honest trust note missing: {}",
        r.note
    );
}

fn sign_minimal_with_test_signer() -> Vec<u8> {
    let e = ContentEngine::open_bytes(fixture_bytes("minimal.pdf")).unwrap();
    e.sign(
        &test_signer(),
        &SignatureOptions {
            field_name: "OxideTrust".to_string(),
            signing_time: Some("D:20260622000000Z".to_string()),
            ..SignatureOptions::default()
        },
    )
    .unwrap()
}

#[test]
fn self_signed_signature_is_valid_but_not_trusted_by_default() {
    // H-3 core guarantee: a cryptographically valid signature from a self-signed
    // certificate must NOT be reported as trusted when no anchors are configured.
    // (The old API exposed only `validity: Valid`, which an integrator would
    // misread as "trusted" — exactly the over-trust this fixes.)
    let engine = ContentEngine::open_bytes(sign_minimal_with_test_signer()).unwrap();
    let r = &engine.verify_signatures().unwrap()[0];
    assert_eq!(
        r.validity,
        SignatureValidity::Valid,
        "integrity must verify"
    );
    assert_eq!(
        r.trust,
        SignatureTrust::NotVerified,
        "no anchors configured -> trust not verified"
    );
    assert_eq!(
        r.status,
        SignatureStatus::ValidUntrusted,
        "overall verdict must be valid-but-untrusted, never trusted"
    );
    assert_ne!(r.status, SignatureStatus::Trusted);
}

#[test]
fn pinning_signer_cert_as_trust_anchor_makes_it_trusted() {
    let signer = test_signer();
    let engine = ContentEngine::open_bytes(sign_minimal_with_test_signer()).unwrap();
    let options =
        VerifyOptions::default().with_trust_anchor_der(signer.signer_certificate_der().unwrap());
    let r = &engine.verify_signatures_with_options(&options).unwrap()[0];
    assert_eq!(r.validity, SignatureValidity::Valid);
    assert_eq!(
        r.trust,
        SignatureTrust::Trusted,
        "signer chains to the pinned anchor and is in validity"
    );
    assert_eq!(r.coverage, Coverage::WholeFile);
    assert_eq!(r.status, SignatureStatus::Trusted);
}

#[test]
fn signature_with_unrelated_trust_anchor_is_not_trusted() {
    // sig_valid.pdf is signed by "Oxide Test Signer". Pinning a DIFFERENT,
    // valid certificate (our test_signer) as the only anchor must not produce a
    // trusted verdict — trust requires an actual chain to a configured anchor.
    let e = ContentEngine::open_bytes(fixture_bytes("sig_valid.pdf")).unwrap();
    let options = VerifyOptions::default()
        .with_trust_anchor_der(test_signer().signer_certificate_der().unwrap());
    let r = &e.verify_signatures_with_options(&options).unwrap()[0];
    assert_eq!(r.validity, SignatureValidity::Valid);
    assert_ne!(
        r.trust,
        SignatureTrust::Trusted,
        "signer does not chain to the unrelated anchor"
    );
    assert_eq!(r.status, SignatureStatus::ValidUntrusted);
}

#[test]
fn modified_after_signing_is_never_trusted_even_with_anchor() {
    let signer = test_signer();
    let mut signed = sign_minimal_with_test_signer();
    signed.extend_from_slice(b"\n% appended after signing\n9 0 obj<<>>endobj\n");

    let engine = ContentEngine::open_bytes(signed).unwrap();
    let options =
        VerifyOptions::default().with_trust_anchor_der(signer.signer_certificate_der().unwrap());
    let r = &engine.verify_signatures_with_options(&options).unwrap()[0];
    // The signer chains to the anchor, but appended content means the signature
    // no longer covers the whole file — so the overall verdict is NOT trusted.
    assert_eq!(r.validity, SignatureValidity::Valid);
    assert_eq!(r.coverage, Coverage::ModifiedAfterSigning);
    assert_eq!(r.status, SignatureStatus::ValidButModified);
    assert_ne!(r.status, SignatureStatus::Trusted);
}

#[test]
fn tampered_signature_overall_status_is_invalid_even_with_anchor() {
    let mut bytes = fixture_bytes("sig_valid.pdf");
    let pos = bytes
        .windows(2)
        .position(|w| w == b"Hi")
        .expect("page content marker present");
    bytes[pos] = b'X';
    let e = ContentEngine::open_bytes(bytes).unwrap();
    let options = VerifyOptions::default()
        .with_trust_anchor_der(test_signer().signer_certificate_der().unwrap());
    let r = &e.verify_signatures_with_options(&options).unwrap()[0];
    assert_eq!(r.validity, SignatureValidity::Invalid);
    assert_eq!(r.status, SignatureStatus::Invalid);
    assert_ne!(r.status, SignatureStatus::Trusted);
}

#[test]
fn tampering_within_signed_range_invalidates() {
    let mut bytes = fixture_bytes("sig_valid.pdf");
    // Flip a byte inside the page content (within the first signed range).
    let pos = bytes
        .windows(2)
        .position(|w| w == b"Hi")
        .expect("page content marker present");
    bytes[pos] = b'X';

    let e = ContentEngine::open_bytes(bytes).unwrap();
    let r = &e.verify_signatures().unwrap()[0];
    assert_eq!(
        r.validity,
        SignatureValidity::Invalid,
        "a byte changed inside the signed range must invalidate the signature"
    );
}

#[test]
fn appending_after_signing_is_valid_but_modified() {
    let mut bytes = fixture_bytes("sig_valid.pdf");
    // Append bytes after the signed ranges (an incremental-update tail).
    bytes.extend_from_slice(b"\n% appended after signing\n1 0 obj<<>>endobj\n");

    let e = ContentEngine::open_bytes(bytes).unwrap();
    let r = &e.verify_signatures().unwrap()[0];
    // The signature is still cryptographically valid for what it covered...
    assert_eq!(r.validity, SignatureValidity::Valid);
    // ...but the document was modified after signing.
    assert_eq!(r.coverage, Coverage::ModifiedAfterSigning);
}

#[test]
fn multiple_signatures_are_all_reported() {
    let e = ContentEngine::open_bytes(fixture_bytes("sig_two.pdf")).unwrap();
    let reports = e.verify_signatures().unwrap();
    assert_eq!(reports.len(), 2, "both signature fields must be reported");

    // Both signatures verify cryptographically.
    for r in &reports {
        assert_eq!(
            r.validity,
            SignatureValidity::Valid,
            "signature {} should be valid",
            r.index
        );
        assert!(r.certificate.is_some());
    }

    // The FIRST signature no longer covers the whole file (the second
    // signature's incremental update is appended after it); the SECOND covers
    // the whole file. This is the standard pdfsig "modified after signing"
    // distinction for the earlier of two signatures.
    assert_eq!(reports[0].coverage, Coverage::ModifiedAfterSigning);
    assert_eq!(reports[1].coverage, Coverage::WholeFile);
}

#[test]
fn unsigned_document_reports_no_signatures() {
    // A normal PDF with no signature fields lists empty (not an error).
    let e = ContentEngine::open_bytes(fixture_bytes("minimal.pdf")).unwrap();
    let reports = e.verify_signatures().unwrap();
    assert!(
        reports.is_empty(),
        "unsigned document must report no signatures"
    );
}

#[test]
fn signer_name_or_metadata_present() {
    // pyHanko records the signer; at minimum a field name is present.
    let e = ContentEngine::open_bytes(fixture_bytes("sig_valid.pdf")).unwrap();
    let r = &e.verify_signatures().unwrap()[0];
    assert!(
        r.field_name.is_some(),
        "the signature field name should be reported"
    );
    assert_eq!(r.field_name.as_deref(), Some("Sig1"));
}
